import React, { createContext, useContext, useState, useEffect } from 'react';
import { userService } from '../services/userService';
import toast from 'react-hot-toast';

const AuthContext = createContext();
export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const stored = localStorage.getItem('grocery_user');
    if (stored) setUser(JSON.parse(stored));
    setLoading(false);
  }, []);

  const login = async (email, password) => {
    try {
      const users = await userService.searchByEmail(email);
      if (!users || !users.email) throw new Error('User not found');
      if (users.password !== password) throw new Error('Wrong password');
      setUser(users);
      localStorage.setItem('grocery_user', JSON.stringify(users));
      toast.success(`Welcome back, ${users.name}! 🌿`);
      return users;
    } catch (err) {
      toast.error(err.message || 'Login failed');
      throw err;
    }
  };

  const register = async (userData) => {
    try {
      const newUser = await userService.createUser({ ...userData, role: 'USER' });
      setUser(newUser);
      localStorage.setItem('grocery_user', JSON.stringify(newUser));
      toast.success('Account created successfully! 🎉');
      return newUser;
    } catch (err) {
      toast.error('Registration failed');
      throw err;
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('grocery_user');
    toast.success('Logged out successfully');
  };

  return (
    <AuthContext.Provider value={{ user, login, register, logout, loading }}>
      {!loading && children}
    </AuthContext.Provider>
  );
};
